CREATE TABLE claude_responses (
    id              BIGSERIAL PRIMARY KEY,
    ts              TIMESTAMPTZ NOT NULL DEFAULT now(),
    model           TEXT        NOT NULL,
    prompt_hash     BYTEA,                        -- SHA-256 of serialised messages
    input_tokens    INT         NOT NULL,
    output_tokens   INT         NOT NULL,
    stop_reason     TEXT,
    content         JSONB       NOT NULL,          -- full content[] array from API
    feature         TEXT,                         -- application-level tag
    user_id         TEXT
);

-- Fast JSONB path queries
CREATE INDEX idx_cr_content_gin  ON claude_responses USING GIN (content);
-- O(1) prompt deduplication lookup
CREATE INDEX idx_cr_hash         ON claude_responses USING HASH (prompt_hash);
-- Time-range scans and retention deletes
CREATE INDEX idx_cr_ts           ON claude_responses (ts DESC);
-- Per-feature cost / usage analytics
CREATE INDEX idx_cr_feature_ts   ON claude_responses (feature, ts DESC);

CREATE TABLE claude_tool_calls (
    id              BIGSERIAL PRIMARY KEY,
    response_id     BIGINT NOT NULL REFERENCES claude_responses(id) ON DELETE CASCADE,
    tool_name       TEXT   NOT NULL,
    tool_use_id     TEXT   UNIQUE NOT NULL,        -- Anthropic's tool_use block id
    input           JSONB  NOT NULL,
    result          JSONB,                        -- populated after execution
    error           TEXT
);

CREATE INDEX idx_tc_response_id ON claude_tool_calls (response_id);
CREATE INDEX idx_tc_input_gin   ON claude_tool_calls USING GIN (input);
CREATE INDEX idx_tc_tool_name   ON claude_tool_calls (tool_name);
